#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,K; scanf("%d %d",&N,&K);
        char S[100005]; scanf("%s",S);
        int total=0; for(int i=0;i<N;i++) total+=S[i]-'0';
        int totalParity=total&1;
        int cnt0=0,cnt1=0,cur=0;
        for(int i=0;i<N-1;i++){
            cur ^= (S[i]-'0');
            if(cur) cnt1++; else cnt0++;
        }
        int ok=0;
        if(K%2==1){
            int p=totalParity;
            if((p?cnt1:cnt0) >= K-1) ok=1;
        }else{
            if(totalParity==0 && (cnt0>cnt1?cnt0:cnt1) >= K-1) ok=1;
        }
        printf("%s\n", ok?"YES":"NO");
    }
    return 0;
}

