import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int K = Integer.parseInt(st.nextToken());
            String S = br.readLine().trim();
            int total = 0;
            for (int i = 0; i < N; i++) total += S.charAt(i) - '0';
            int totalParity = total & 1;
            int cnt0 = 0, cnt1 = 0, cur = 0;
            for (int i = 0; i < N - 1; i++) {
                cur ^= (S.charAt(i) - '0');
                if (cur == 0) cnt0++; else cnt1++;
            }
            boolean ok = false;
            if (K % 2 == 1) {
                int p = totalParity;
                ok = (p == 0 ? cnt0 : cnt1) >= K - 1;
            } else {
                if (totalParity == 0 && Math.max(cnt0, cnt1) >= K - 1) ok = true;
            }
            out.append(ok ? "YES" : "NO").append('\n');
        }
        System.out.print(out.toString());
