#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it))
        S = next(it)
        total = S.count('1')
        totalParity = total & 1
        cnt0 = cnt1 = 0
        cur = 0
        for i in range(N-1):
            cur ^= (ord(S[i]) - 48)
            if cur:
                cnt1 += 1
            else:
                cnt0 += 1
        ok = False
        if K % 2 == 1:
            p = totalParity
            ok = (cnt1 if p else cnt0) >= K-1
        else:
            if totalParity == 0 and max(cnt0, cnt1) >= K-1:
                ok = True
        out.append('YES' if ok else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

